using Microsoft.Extensions.AI;
using OpenAI;

// --- Configuration ---
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable to run this agent.");

var modelId = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini-2024-07-18";

// --- Build the chat client ---
IChatClient chatClient = new OpenAIClient(apiKey)
    .GetChatClient(modelId)
    .AsIChatClient();

// --- Create tools ---
var notepad = new Notepad();

var tools = new List<AITool>
{
    AIFunctionFactory.Create(WebResearchTools.SearchWeb),
    AIFunctionFactory.Create(WebResearchTools.FetchPage),
    AIFunctionFactory.Create(notepad.SaveNote),
    AIFunctionFactory.Create(notepad.GetNotes),
};

// --- Create the agent ---
var agent = new ChatClientAgent(
    chatClient,
    instructions: """
        You are a research agent. Your job is to thoroughly research a topic by:
        1. Searching the web for relevant information using the SearchWeb tool.
        2. Fetching and reading promising web pages using the FetchPage tool.
        3. Saving key findings as notes using the SaveNote tool.
        4. Providing a comprehensive summary of your research.

        Research strategy:
        - Start with a broad search, then drill into specific subtopics.
        - Fetch at least 2-3 pages to get diverse perspectives.
        - Save a note for each important finding before moving on.
        - Always cite your sources with URLs in the final summary.
        """,
    name: "ResearchAgent",
    description: "An AI agent that researches topics using web search and note-taking",
    tools: tools);

// --- Get the research topic ---
Console.Write("Enter a research topic: ");
var topic = Console.ReadLine()?.Trim();

if (string.IsNullOrEmpty(topic))
{
    Console.WriteLine("No topic provided. Exiting.");
    return;
}

Console.WriteLine($"\n🔍 Researching: {topic}\n");

// --- Run the agent with streaming ---
var session = await agent.CreateSessionAsync(
    conversationId: Guid.NewGuid().ToString());

var runOptions = new ChatClientAgentRunOptions
{
    ChatOptions = new ChatOptions
    {
        Temperature = 0f,
        MaxOutputTokens = 4096,
    },
};

await foreach (var update in agent.RunStreamingAsync(
    $"Research the following topic and provide a comprehensive summary: {topic}",
    session,
    runOptions))
{
    Console.Write(update.Text);
}

// --- Display collected notes ---
var notes = notepad.GetNotes();
if (notes.Count > 0)
{
    Console.WriteLine("\n\n📝 Notes collected during research:\n");
    foreach (var note in notes)
    {
        var preview = note.Content.Length > 120
            ? note.Content[..120] + "..."
            : note.Content;
        Console.WriteLine($"  • [{note.Title}] {preview}");
    }
}

Console.WriteLine();

