 using System.ComponentModel;
 using System.Text.RegularExpressions;
 using Microsoft.Agents.AI;
 using Microsoft.Extensions.AI;
 using OpenAI;

 // --- Configuration ---
 var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
     ?? throw new InvalidOperationException(
         "Set the OPENAI_API_KEY environment variable to run this agent.");

 var modelId = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini-2024-07-18";

 // --- Build the chat client ---
 IChatClient chatClient = new OpenAIClient(apiKey)
     .GetChatClient(modelId)
     .AsIChatClient();

 // --- Create tools ---
 var notepad = new Notepad();

 var tools = new List<AITool>
 {
     AIFunctionFactory.Create(WebResearchTools.SearchWeb),
     AIFunctionFactory.Create(WebResearchTools.FetchPage),
     AIFunctionFactory.Create(notepad.SaveNote),
     AIFunctionFactory.Create(notepad.GetNotes),
 };

 // --- Create the agent ---
 var agent = new ChatClientAgent(
     chatClient,
     instructions: """
         You are a research agent. Your job is to thoroughly research a topic by:
         1. Searching the web for relevant information using the SearchWeb tool.
         2. Fetching and reading promising web pages using the FetchPage tool.
         3. Saving key findings as notes using the SaveNote tool.
         4. Providing a comprehensive summary of your research.

         Research strategy:
         - Start with a broad search, then drill into specific subtopics.
         - Fetch at least 2-3 pages to get diverse perspectives.
         - Save a note for each important finding before moving on.
         - Always cite your sources with URLs in the final summary.
         """,
     name: "ResearchAgent",
     description: "An AI agent that researches topics using web search and note-taking",
     tools: tools);

 // --- Get the research topic ---
 Console.Write("Enter a research topic: ");
 var topic = Console.ReadLine()?.Trim();

 if (string.IsNullOrEmpty(topic))
 {
     Console.WriteLine("No topic provided. Exiting.");
     return;
 }

 Console.WriteLine($"\n🔍 Researching: {topic}\n");

 // --- Run the agent with streaming ---
 var session = await agent.CreateSessionAsync(
     conversationId: Guid.NewGuid().ToString());

 var runOptions = new ChatClientAgentRunOptions
 {
     ChatOptions = new ChatOptions
     {
         Temperature = 0f,
         MaxOutputTokens = 4096,
     },
 };

 await foreach (var update in agent.RunStreamingAsync(
     $"Research the following topic and provide a comprehensive summary: {topic}",
     session,
     runOptions))
 {
     Console.Write(update.Text);
 }

 // --- Display collected notes ---
 var notes = notepad.GetNotes();
 if (notes.Count > 0)
 {
     Console.WriteLine("\n\n📝 Notes collected during research:\n");
     foreach (var note in notes)
     {
         var preview = note.Content.Length > 120
             ? note.Content[..120] + "..."
             : note.Content;
         Console.WriteLine($"  • [{note.Title}] {preview}");
     }
 }

 Console.WriteLine();

 // ---------------------------------------------------------------------------
 // Tool implementations
 // ---------------------------------------------------------------------------

 /// <summary>Web search and page-fetching tools for the research agent.</summary>
 static partial class WebResearchTools
 {
     private static readonly HttpClient s_httpClient = new()
     {
         Timeout = TimeSpan.FromSeconds(15),
         DefaultRequestHeaders =
         {
             { "User-Agent", "Mozilla/5.0 (compatible; ResearchAgent/1.0)" },
         },
     };

     [Description("Searches the web for a query and returns a list of result titles, URLs, and snippets.")]
     public static async Task<IReadOnlyList<SearchResult>> SearchWeb(
         [Description("The search query")] string query)
     {
         try
         {
             var encoded = Uri.EscapeDataString(query);
             var url = $"https://html.duckduckgo.com/html/?q={encoded}";
             var html = await s_httpClient.GetStringAsync(url);

             var results = new List<SearchResult>();

             // Extract result links and snippets from DuckDuckGo HTML
             var linkMatches = ResultLinkRegex().Matches(html);
             var snippetMatches = SnippetRegex().Matches(html);

             for (var i = 0; i < Math.Min(linkMatches.Count, 5); i++)
             {
                 var resultUrl = System.Net.WebUtility.UrlDecode(
                     linkMatches[i].Groups[1].Value);
                 var title = StripHtml(linkMatches[i].Groups[2].Value);
                 var snippet = i < snippetMatches.Count
                     ? StripHtml(snippetMatches[i].Groups[1].Value)
                     : "";

                 // DuckDuckGo wraps URLs in a redirect; extract the actual URL
                 var actualUrl = ExtractRedirectUrl(resultUrl);

                 results.Add(new SearchResult(title.Trim(), actualUrl, snippet.Trim()));
             }

             return results.Count > 0
                 ? results
                 : [new SearchResult("No results", "", $"No results found for: {query}")];
         }
         catch (Exception ex)
         {
             return [new SearchResult("Error", "", $"Search failed: {ex.Message}")];
         }
     }

     [Description("Fetches a web page and returns its text content (HTML tags stripped). Use this to read a page found via SearchWeb.")]
     public static async Task<string> FetchPage(
         [Description("The full URL of the web page to fetch")] string url)
     {
         try
         {
             var html = await s_httpClient.GetStringAsync(url);

             // Remove script/style blocks then strip remaining tags
             var text = ScriptStyleRegex().Replace(html, " ");
             text = HtmlTagRegex().Replace(text, " ");
             text = System.Net.WebUtility.HtmlDecode(text);
             text = ExcessWhitespaceRegex().Replace(text, " ").Trim();

             // Limit length to avoid exceeding token budgets
             const int maxLength = 6_000;
             if (text.Length > maxLength)
             {
                 text = text[..maxLength] + "\n\n[Content truncated]";
             }

             return text;
         }
         catch (Exception ex)
         {
             return $"Failed to fetch page: {ex.Message}";
         }
     }

     private static string ExtractRedirectUrl(string duckDuckGoUrl)
     {
         // DuckDuckGo links look like //duckduckgo.com/l/?uddg=https%3A%2F%2F...&rut=...
         var match = RedirectUrlRegex().Match(duckDuckGoUrl);
         return match.Success
             ? Uri.UnescapeDataString(match.Groups[1].Value)
             : duckDuckGoUrl;
     }

     private static string StripHtml(string html)
     {
         var text = HtmlTagRegex().Replace(html, "");
         return System.Net.WebUtility.HtmlDecode(text);
     }

     [GeneratedRegex("""<a[^>]+class="result__a"[^>]*href="([^"]*)"[^>]*>(.*?)</a>""", RegexOptions.Singleline)]
     private static partial Regex ResultLinkRegex();

     [GeneratedRegex("""<a[^>]+class="result__snippet"[^>]*>(.*?)</a>""", RegexOptions.Singleline)]
     private static partial Regex SnippetRegex();

     [GeneratedRegex("""uddg=([^&]+)""")]
     private static partial Regex RedirectUrlRegex();

     [GeneratedRegex("""<(script|style)[^>]*>.*?</\1>""", RegexOptions.Singleline | RegexOptions.IgnoreCase)]
     private static partial Regex ScriptStyleRegex();

     [GeneratedRegex("""<[^>]+>""")]
     private static partial Regex HtmlTagRegex();

     [GeneratedRegex("""\s{2,}""")]
     private static partial Regex ExcessWhitespaceRegex();
 }

 /// <summary>A single web search result.</summary>
 record SearchResult(string Title, string Url, string Snippet);

 /// <summary>Note-taking tool that stores research findings in memory.</summary>
 class Notepad
 {
     private readonly List<Note> _notes = [];

     [Description("Saves a research note. Use this to record important findings during research.")]
     public string SaveNote(
         [Description("A short title for the note")] string title,
         [Description("The detailed content of the note")] string content)
     {
         _notes.Add(new Note(title, content, DateTime.UtcNow));
         return $"Note saved: '{title}' ({_notes.Count} total notes)";
     }

     [Description("Returns all saved research notes.")]
     public IReadOnlyList<Note> GetNotes() => _notes.AsReadOnly();
 }

 /// <summary>A single research note.</summary>
 record Note(string Title, string Content, DateTime SavedAt);
